```typescript
function retryWithBackoff<T>(fn: () => Promise<T>, maxRetries = 5, minDelay = 100, maxDelay = 2000): Promise<T> {
    let attempt = 0;
    const execute = async (): Promise<T> => {
        try {
            return await fn();
        } catch (error) {
            if (++attempt > maxRetries) throw error;
            const delay = Math.min(minDelay * Math.pow(2, attempt), maxDelay);
            await new Promise(resolve => setTimeout(resolve, delay));
            return execute();
        }
    };
    return execute();
}
```

This function will retry the provided asynchronous function up to `maxRetries` times, increasing the delay between attempts exponentially from `minDelay` to `maxDelay`. Adjust these parameters based on your specific use case.

