    this.initialEnergy -= energyDrift;
    if (this.initialEnergy < 0) {
      this.initialEnergy = 0;
    }
    this.lastUpdate = currentTime;
  }

  getRemainingEnergy(): number {
    return this.initialEnergy;
  }
}
```

